import logging
import os

from core_lib.client.client_base import ClientBase
from core_lib.helpers.constants import MediaType, HttpHeaders
from interest_core_lib.client.interest_handler import InterestHandler
from interest_core_lib.constants import CLIENT_TIMEOUT
import tmdbsimple as tmdb


class TMDBv4InterestHandler(ClientBase, InterestHandler):

    def __init__(self, api_key: str, access_token: str, is_movie: bool):
        InterestHandler.__init__(self)
        ClientBase.__init__(self, 'https://api.themoviedb.org/4/')
        self.api_key = api_key  # V3 key
        self.access_token = access_token
        self.is_movie = is_movie
        self.set_timeout(CLIENT_TIMEOUT)
        self.timeout = CLIENT_TIMEOUT
        self.logger = logging.getLogger(self.__class__.__name__)
        header = {
            HttpHeaders.AUTHORIZATION.value: f'Bearer {self.access_token}',
            HttpHeaders.CONTENT_TYPE.value: f'{MediaType.APPLICATION_JSON.value};charset=utf-8'
        }
        self.set_headers(header)
        tmdb.API_KEY = self.api_key
        self.icon_path_str = os.path.join(os.path.dirname(__file__), 'tmdb.png')

    def connect(self):
        response = self._post('auth/request_token', data={'request_token': self.access_token}).json()
        if not response['success']:
            raise ValueError(response)
        self.request_token = response['request_token']

    def to_search_results(self, term: str):
        # search_type = 'movie' if self.is_movie else 'tv'
        # return self._get(f'discover/{search_type}?primary_release_date.gte=2014-09-15&primary_release_date.lte=2014-10-22').json()['results']
        if self.is_movie:
            return self._filter_results(tmdb.Search().movie(query=term)['results'])
        else:
            return self._filter_results(tmdb.Search().tv(query=term)['results'])

    def to_interest_item(self, data: dict):
        return self._to_interest_search_result(data)

    def icon_path(self):
        return self.icon_path_str

    def get_full_info(self, external_id):
        # https://www.themoviedb.org/talk/61a8d03d875d1a008b592187
        if self.is_movie:
            return tmdb.Movies(external_id).info()
        else:
            return tmdb.TV(external_id).info()
        # r = self._get(f'find/movie?id{external_id}').json()
        # return self._to_interest_search_result(r)

    def _filter_results(self, results):
        return filter(lambda result: result and result.get('poster_path'), results)

    def _to_interest_search_result(self, result):
        creator = ''
        if 'created_by' in result:
            try:
                creator = ', '.join([c['name'] for c in result.get('created_by')])
            except Exception as ex:
                self.logger.error('error while loading creator, id: `{}`m is_movie: `{}`'.format(result.get('id'), self.is_movie))
                self.logger.exception(ex)

        poster_path = result.get('poster_path') or result.get('backdrop_path')
        full_info = self._get_full_info(result['id'])
        release_date = result.get('release_date') or result.get('first_air_date')
        production_countries = [country.get('name') for country in full_info.get('production_countries') or []]
        if not production_countries:
            production_countries = full_info.get('origin_country') or []
        return {
            'external_id': result['id'],
            'label': result.get('name') or result.get('title'),
            'description': result['overview'],
            'image_url': self._image_url(poster_path, False) if poster_path else None,
            'thumbnail_url': self._image_url(poster_path, True) if poster_path else None,
            'url': 'https://www.themoviedb.org/{}/{}'.format('movie' if self.is_movie else 'tv', result['id']),
            'preview_url': None,
            'source': 'tmdb',
            'creator': creator,
            'meta_data': {},
            'popularity': result.get('popularity'),
            'language': result.get('original_language'),
            'release_year': release_date.split('-')[0] if release_date else None,
            'cast': full_info['cast'],
            'directors': full_info['directors'],
            'writers': full_info['writers'],
            'genres': full_info['genres'],
            'keywords': full_info.get('keywords', []),
            'runtime': full_info.get('runtime', None),
            'user_rating': full_info['vote_average'],
            'vote_count': full_info.get('vote_count'),
            'original_title': result.get('original_title') or result.get('original_name') or full_info.get('original_title') or full_info.get('original_name'),
            'production_countries': production_countries,
        }

    def _image_url(self, file_path: str, is_thumbnail: bool):
        thumbnail_size = 'w200'
        full_size = 'w400'
        return f'https://image.tmdb.org/t/p/{thumbnail_size if is_thumbnail else full_size}/{file_path.strip("/")}'

    def _get_full_info(self, id: int):
        if self.is_movie:
            media = tmdb.Movies(id=id)
            keywords_key = 'keywords'
        else:
            media = tmdb.TV(id=id)
            keywords_key = 'results'
        full_info = media.info()
        credits = media.credits()
        keywords = []
        try:
            keywords = [keyword['name'] for keyword in media.keywords().get(keywords_key, [])]
        except Exception:
            self.logger.warning('unable to load keywords, id: `{}`, is_movie: `{}`'.format(id, self.is_movie))
        cast = [cast_member['name'] for cast_member in credits['cast']]
        directors = [crew['name'] for crew in credits['crew'] if crew['job'] == 'Director']
        writers = [crew['name'] for crew in credits['crew'] if crew.get('job') in ('Writer', 'Screenplay', 'Author', 'Story', 'Novel')]
        genres = [genre['name'] for genre in full_info['genres']]
        return {**full_info, 'cast': cast, 'directors': directors, 'writers': writers, 'genres': genres, 'keywords': keywords}

    def _get_cast_members(self, cast_list: list):
        cast_members = []
        for cast_member in cast_list:
            cast_members.append(cast_member['name'])
        return cast_members

