def images_links_compare_desc(item):
    return 2000 - int(item['height'])


class ArtsyInterestHandler(ClientBase, InterestHandler):

    def __init__(self, client_id: str, client_secret: str):
        InterestHandler.__init__()
        ClientBase.__init__(self, 'https://api.artsy.net/api')
        self.logger = logging.getLogger(self.__class__.__name__)
        self._client_id = client_id
        self._client_secret = client_secret
        self.set_timeout(CLIENT_TIMEOUT)
        self.icon_path_str = os.path.join(os.path.dirname(__file__), 'artsy.png')

    def connect(self):
        result = self._post('tokens/xapp_token?client_id={}&client_secret={}'.format(self._client_id, self._client_secret), timeout=10).json()
        token = result['token']
        self.set_headers({'X-XAPP-Token': token})

    def to_search_results(self, term: str):
        try:
            return self._get('search', params={'q': '{}more:pagemap:metatags-og_type:artwork'.format(term)})
        except BaseException as e:
            self.is_online_flag = False
            self.logger.error(e)
            raise e

    def to_interest_item(self, data: dict):
        album = data['album']
        images = sorted(album.get('images') or [], key=images_links_compare_desc)
        image_url = None
        if images:
            image_url = images[0]['url']
        return {
            'external_id': data['id'],
            'label': data['name'],
            'description': album.get('name') or '',
            'url': data['external_urls']['spotify'],
            'image_url': image_url,
            'thumbnail_url': image_url,
            'preview_url': None,
            'source': 'artsy',
            'creator': '',
            'meta_data': {},
        }

    def get_full_info(self, external_id):
        return {}

    def icon_path(self):
        return self.icon_path_str

    def close(self):
        self.session.close()

