        tmdb.API_KEY = self.api_key
        self.icon_path_str = os.path.join(os.path.dirname(__file__), 'tmdb.png')

    def connect(self):
        response = self._post('auth/request_token', data={'request_token': self.access_token}).json()
        if not response['success']:
            raise ValueError(response)
        self.request_token = response['request_token']

    def to_search_results(self, term: str):
        # search_type = 'movie' if self.is_movie else 'tv'
