from core_lib.connection.solr_connection_factory import SolrConnectionFactory
from core_lib.data_layers.service.service import Service
from interest_core_lib.client.core_value_activity.activity_interest_handler import ActivityInterestHandler
from interest_core_lib.client.core_value_activity.core_value_interest_handler import CoreValueInterestHandler

color_change = 0.1


class InterestSeedService(Service):

    def __init__(self, solr_data_session: SolrConnectionFactory):
        self._solr = solr_data_session

    def _seed(self, file_path: str, interest_type: int):
        add_data = []
        last_color = None
        with open(file_path, encoding="utf-8") as file:
            for line in file:
                columns = line.strip().split(',')
                english = columns[0].strip().lower()
                hebrew = columns[1].strip().lower()
                color = columns[2]

                interest_id = english.replace(' ', '_')

                if not color:
                    color_rgb = hex_to_rgb(last_color)
                    color_changed = adjust_color_lighten(color_rgb[0], color_rgb[1], color_rgb[2], color_change)
                    color = rgb_to_hex(*color_changed)

                add_data.append({
                    'interest_id': interest_id,
                    'interest_values': [english, hebrew],
                    'interest_type': interest_type,
                    'color': color,
                })
                last_color = color

        with self._solr.get() as session:
            session.add(add_data, overwrite=True)

    def seed_core_values(self, file_path: str):
        self._seed(file_path, CoreValueInterestHandler.INTEREST_TYPE)

    def seed_activities(self, file_path: str):
        self._seed(file_path, ActivityInterestHandler.INTEREST_TYPE)


def adjust_color_darken(r,g,b, factor):
        return [
            r*factor,
            g*factor,
            b*factor
        ]


def adjust_color_lighten(r,g,b, factor):
    return [int(255 - (255-r)*(1-factor)),
            int(255 - (255-g)*(1-factor)),
            int(255 - (255-b)*(1-factor))]


def hex_to_rgb(hex_color):
    h = hex_color.lstrip('#')
    return tuple(int(h[i:i + 2], 16) for i in (0, 2, 4))


def rgb_to_hex(r,g,b):
    return "#%02x%02x%02x" % (r,g,b)

