import os

from core_lib.connection.solr_connection_factory import SolrConnectionFactory
from interest_core_lib.client.interest_handler import InterestHandler


class SolrInterestHandler(InterestHandler):

    def __init__(self, interest_type: int):
        InterestHandler.__init__(self)
        self._interest_type = interest_type
        self._solr = None
        self.icon_path_str = os.path.join(os.path.dirname(__file__), 'una.png')

    def connect(self):
        pass

    def set_solr_client(self, solr_client: SolrConnectionFactory):
        self._solr = solr_client

    def to_search_results(self, term: str):
        if not term:
            return []
        with self._solr.get() as session:
            query = {'rows': 20}
            term_search = '*'
            for ch in term:
                term_search = term_search + ch + '*'

            filter_queries = [
                'interest_type:{}'.format(self._interest_type),
                'interest_values:{}'.format(term_search)
            ]
            query['fq'] = filter_queries
            return session.search("*:*", **query)

    def to_interest_item(self, data: dict):
        return {
            'external_id': data['interest_id'],
            'label': data['interest_id'],
            'description': '',
            'image_url': '{}.png'.format(data['interest_id']),
            'thumbnail_url': '{}.png'.format(data['interest_id']),
            'preview_url': None,
            'url': '',
            'source': 'interest_core_lib',
            'creator': '',
            'meta_data': {'color': data['color']},
        }

    def get_full_info(self, external_id):
        with self._solr.get() as session:
            query = {'fq': ['interest_id:{}'.format(external_id),
                            'interest_type:{}'.format(self._interest_type)],
                     'rows': 20}
            result = session.search("*:*", **query)
            if result.docs:
                return dict(result.docs[0])

    def close(self):
        pass
        # print(f'SolrInterestHandler.close {self._interest_type}')
        # traceback.print_stack()
    #     if self._solr:
    #         with self._solr.get() as solr:
    #             solr.get_session().close()

    def icon_path(self):
        return self.icon_path_str

    def suggestions(self, ids: list):
        with self._solr.get() as session:
            query = {'rows': 250}
            filter_queries = [f'interest_type:{self._interest_type}']
            if ids and len(ids) > 0:
                ids_str = ' '.join(ids)
                filter_queries.append(f'interest_id:({ids_str})')

            query['fq'] = filter_queries
            query['sort'] = 'interest_id asc'
            return [self.to_interest_item(item) for item in session.search("*:*", **query)]

